<script setup lang="ts">
import { computed, onMounted, reactive, ref } from "vue";
import { UiTable, type UiTableColumn } from "@moecraft/ui";
import type { CatalogEntityType, CatalogOverview } from "@moecraft/shared";
import { apiRequest } from "../../../api";

type Row = Record<string, unknown> & { id: string; nameZhCn: string; nameEnUs?: string | null; isActive: boolean; productCount?: number; slug?: string; code?: string };
const types: Array<{ key: CatalogEntityType; label: string }> = [{key:"categories",label:"多级类目"},{key:"brands",label:"品牌"},{key:"franchises",label:"作品 / IP"},{key:"characters",label:"角色"},{key:"tags",label:"标签"},{key:"attribute-templates",label:"属性模板"}];
const activeType = ref<CatalogEntityType>("categories"), overview = ref<CatalogOverview | null>(null), loading = ref(true), busy = ref(false), keyword = ref(""), status = ref("ALL"), editingId = ref<string | null>(null), modal = ref(false), error = ref("");
const form = reactive({ slug:"", code:"", nameZhCn:"", nameEnUs:"", descriptionZhCn:"", descriptionEnUs:"", parentId:"", franchiseId:"", categoryId:"", inputType:"TEXT", options:"", isRequired:false, isActive:true, sortOrder:0 });
const columns: UiTableColumn[] = [{key:"name",label:"名称",width:"28%"},{key:"key",label:"Slug / Code",width:"22%"},{key:"relation",label:"上级 / 归属",width:"20%"},{key:"references",label:"商品引用",width:"10%",align:"center"},{key:"status",label:"状态",width:"8%"},{key:"actions",label:"操作",width:"12%",align:"right"}];
const source = computed<Row[]>(() => { if(!overview.value)return[];const map={categories:overview.value.categories,brands:overview.value.brands,franchises:overview.value.franchises,characters:overview.value.characters,tags:overview.value.tags,"attribute-templates":overview.value.attributeTemplates};return map[activeType.value] as Row[]; });
const rows = computed(() => source.value.filter(item => (!keyword.value || `${item.nameZhCn}${item.nameEnUs??""}${item.slug??item.code??""}`.toLowerCase().includes(keyword.value.toLowerCase())) && (status.value==="ALL" || item.isActive===(status.value==="ACTIVE"))).map(item=>({...item,name:item.nameZhCn,key:item.slug??item.code,relation:relation(item),references:item.productCount??0,status:item.isActive?"启用":"停用",actions:item.id})));
function relation(row:Row){if(activeType.value==="categories")return sourceName("categories",row.parentId);if(activeType.value==="characters")return String(row.franchiseName??"");if(activeType.value==="attribute-templates")return sourceName("categories",row.categoryId);return"—"}
function sourceName(type:"categories"|"franchises",id:unknown){if(!id||!overview.value)return"顶级 / 无";return overview.value[type].find(item=>item.id===id)?.nameZhCn??"未知"}
function reset(){Object.assign(form,{slug:"",code:"",nameZhCn:"",nameEnUs:"",descriptionZhCn:"",descriptionEnUs:"",parentId:"",franchiseId:"",categoryId:"",inputType:"TEXT",options:"",isRequired:false,isActive:true,sortOrder:0})}
function openCreate(){editingId.value=null;reset();modal.value=true}
function openEdit(row:Row){editingId.value=row.id;Object.assign(form,{...row,parentId:row.parentId??"",franchiseId:row.franchiseId??"",categoryId:row.categoryId??"",options:Array.isArray(row.options)?row.options.join("\n"):""});modal.value=true}
async function load(){loading.value=true;try{overview.value=await apiRequest<CatalogOverview>("/catalog/admin")}catch{error.value="目录数据加载失败"}finally{loading.value=false}}
async function save(){busy.value=true;error.value="";try{const attribute=activeType.value==="attribute-templates";const payload=attribute?{code:form.code,nameZhCn:form.nameZhCn,nameEnUs:form.nameEnUs||undefined,categoryId:form.categoryId||undefined,inputType:form.inputType,options:form.options.split("\n").map(v=>v.trim()).filter(Boolean),isRequired:form.isRequired,isActive:form.isActive,sortOrder:Number(form.sortOrder)}:{slug:form.slug,nameZhCn:form.nameZhCn,nameEnUs:form.nameEnUs||undefined,descriptionZhCn:form.descriptionZhCn||undefined,descriptionEnUs:form.descriptionEnUs||undefined,parentId:activeType.value==="categories"?form.parentId||undefined:undefined,franchiseId:activeType.value==="characters"?form.franchiseId:undefined,isActive:form.isActive,sortOrder:Number(form.sortOrder)};await apiRequest(`/catalog/${activeType.value}${editingId.value?`/${editingId.value}`:""}`,{method:editingId.value?"PUT":"POST",body:JSON.stringify(payload)});modal.value=false;await load()}catch{error.value="保存失败，请检查唯一标识、必填项或层级关系"}finally{busy.value=false}}
async function toggle(row:Row){await apiRequest(`/catalog/${activeType.value}/${row.id}/status`,{method:"PATCH",body:JSON.stringify({isActive:!row.isActive})});await load()}
async function remove(row:Row){if(!confirm(`确认删除“${row.nameZhCn}”吗？被引用时系统会自动改为禁用。`))return;await apiRequest(`/catalog/${activeType.value}/${row.id}`,{method:"DELETE"});await load()}
onMounted(load);
</script>
<template><section class="catalog-page content-scroll"><div class="shell"><header class="hero"><div><span>CATALOG GOVERNANCE</span><h1>目录资料中心</h1><p>统一维护商城分类、品牌、作品 IP、角色、标签与商品属性规范。</p></div><button @click="openCreate">＋ 新增{{types.find(v=>v.key===activeType)?.label}}</button></header><p v-if="error" class="error">{{error}}</p><nav class="tabs"><button v-for="item in types" :key="item.key" :class="{active:activeType===item.key}" @click="activeType=item.key">{{item.label}}<small>{{overview ? (item.key==='attribute-templates'?overview.attributeTemplates:overview[item.key]).length : 0}}</small></button></nav><section class="panel"><div class="filters"><input v-model="keyword" placeholder="搜索中英文名称或唯一标识"><select v-model="status"><option value="ALL">全部状态</option><option value="ACTIVE">已启用</option><option value="INACTIVE">已停用</option></select></div><div v-if="loading" class="loading">正在加载目录数据…</div><UiTable v-else :columns="columns" :rows="rows" empty-text="暂无符合条件的数据"><template #cell-name="{row}"><div class="name"><b>{{row.nameZhCn}}</b><small>{{row.nameEnUs||'未填写英文翻译'}}</small></div></template><template #cell-status="{row}"><em :class="{off:!row.isActive}">{{row.isActive?'启用':'停用'}}</em></template><template #cell-actions="{row}"><div class="actions"><button @click="openEdit(row as Row)">编辑</button><button @click="toggle(row as Row)">{{row.isActive?'停用':'启用'}}</button><button class="danger" @click="remove(row as Row)">删除</button></div></template></UiTable></section></div><Teleport to="body"><div v-if="modal" class="mask" @mousedown.self="modal=false"><form class="modal" @submit.prevent="save"><header><div><small>{{editingId?'EDIT':'CREATE'}}</small><h2>{{editingId?'编辑':'新增'}}{{types.find(v=>v.key===activeType)?.label}}</h2></div><button type="button" @click="modal=false">×</button></header><div class="fields"><label><span>中文名称 *</span><input v-model="form.nameZhCn" required></label><label><span>英文名称</span><input v-model="form.nameEnUs"></label><label v-if="activeType!=='attribute-templates'"><span>Slug *</span><input v-model="form.slug" required pattern="[a-z0-9]+(?:-[a-z0-9]+)*"></label><label v-else><span>属性代码 *</span><input v-model="form.code" required></label><label><span>排序</span><input v-model.number="form.sortOrder" type="number" min="0"></label><label v-if="activeType==='categories'"><span>上级类目</span><select v-model="form.parentId"><option value="">顶级类目</option><option v-for="item in overview?.categories.filter(v=>v.id!==editingId)" :key="item.id" :value="item.id">{{item.nameZhCn}}</option></select></label><label v-if="activeType==='characters'"><span>所属作品 / IP *</span><select v-model="form.franchiseId" required><option value="">请选择</option><option v-for="item in overview?.franchises" :key="item.id" :value="item.id">{{item.nameZhCn}}</option></select></label><label v-if="activeType==='attribute-templates'"><span>适用类目</span><select v-model="form.categoryId"><option value="">全部类目</option><option v-for="item in overview?.categories" :key="item.id" :value="item.id">{{item.nameZhCn}}</option></select></label><label v-if="activeType==='attribute-templates'"><span>输入类型</span><select v-model="form.inputType"><option>TEXT</option><option>NUMBER</option><option>SELECT</option><option>MULTI_SELECT</option><option>BOOLEAN</option></select></label><label v-if="activeType==='attribute-templates'" class="full"><span>选项（每行一项）</span><textarea v-model="form.options" rows="4" /></label><label v-if="['categories','brands','franchises'].includes(activeType)" class="full"><span>中文说明</span><textarea v-model="form.descriptionZhCn" rows="3" /></label><label class="check"><input v-model="form.isActive" type="checkbox">立即启用</label><label v-if="activeType==='attribute-templates'" class="check"><input v-model="form.isRequired" type="checkbox">商品必填</label></div><footer><button type="button" @click="modal=false">取消</button><button class="primary" :disabled="busy">{{busy?'保存中…':'保存'}}</button></footer></form></div></Teleport></section></template>
<style scoped lang="less">.catalog-page{background:var(--shell-bg);color:var(--text)}.shell{width:min(1320px,100%);margin:auto}.hero{display:flex;align-items:center;justify-content:space-between;padding:28px 34px;border:1px solid var(--border);border-radius:20px;background:linear-gradient(120deg,var(--accent-soft),var(--surface) 60%)}.hero span,.modal header small{color:var(--accent);font-size:10px;font-weight:800;letter-spacing:.16em}.hero h1{margin:8px 0 5px;font-size:30px}.hero p{margin:0;color:var(--text-muted);font-size:12px}.hero button,.primary{padding:12px 18px;border:0;border-radius:10px;background:var(--accent);color:#fff;font-weight:700;cursor:pointer}.tabs{display:flex;gap:8px;margin:18px 0;overflow:auto}.tabs button{display:flex;align-items:center;gap:8px;padding:10px 14px;border:1px solid var(--border);border-radius:10px;background:var(--surface);color:var(--text-secondary);white-space:nowrap;cursor:pointer}.tabs button.active{border-color:var(--accent);background:var(--accent-soft);color:var(--accent)}.tabs small{padding:2px 6px;border-radius:999px;background:var(--surface-raised)}.panel{overflow:hidden;border:1px solid var(--border);border-radius:17px;background:var(--surface);box-shadow:var(--shadow)}.filters{display:grid;grid-template-columns:1fr 180px;gap:12px;padding:16px;border-bottom:1px solid var(--border)}input,select,textarea{width:100%;padding:11px 12px;border:1px solid var(--border);border-radius:9px;background:var(--surface-raised);color:var(--text);outline:none}.name{display:grid;gap:3px}.name small{color:var(--text-muted)}em{padding:4px 8px;border-radius:999px;background:var(--success-soft);color:var(--success);font-style:normal}.off{background:var(--danger-soft);color:var(--danger)}.actions{display:flex;justify-content:flex-end;gap:5px}.actions button{padding:6px 8px;border:0;border-radius:7px;background:var(--surface-raised);color:var(--text-secondary);cursor:pointer}.actions .danger{color:var(--danger)}.loading,.error{padding:18px}.error{border-radius:10px;background:var(--danger-soft);color:var(--danger)}.mask{position:fixed;z-index:1000;inset:0;display:grid;place-items:center;padding:20px;background:rgba(12,16,32,.5);backdrop-filter:blur(5px)}.modal{width:min(720px,100%);max-height:calc(100dvh - 40px);overflow:auto;border:1px solid var(--border);border-radius:18px;background:var(--surface);box-shadow:0 30px 80px rgba(12,16,35,.3)}.modal header{display:flex;align-items:center;justify-content:space-between;padding:22px 24px;border-bottom:1px solid var(--border)}.modal h2{margin:6px 0 0}.modal header button{width:34px;height:34px;border:0;border-radius:8px;background:var(--surface-raised);font-size:22px}.fields{display:grid;grid-template-columns:1fr 1fr;gap:16px;padding:24px}.fields label{display:grid;gap:7px}.fields span{font-size:11px;color:var(--text-secondary)}.fields .full{grid-column:1/-1}.fields .check{display:flex;align-items:center}.check input{width:16px}.modal footer{display:flex;justify-content:flex-end;gap:10px;padding:18px 24px;border-top:1px solid var(--border)}.modal footer button:not(.primary){padding:11px 17px;border:0;border-radius:9px;background:var(--surface-raised)}@media(max-width:700px){.hero{align-items:flex-start;flex-direction:column;gap:18px}.filters,.fields{grid-template-columns:1fr}.fields .full{grid-column:auto}}</style>
